def find_matches_in_quran(query, qdata):
    nq = normalize_arabic(query)
    results = []
    for entry in qdata:
        nt = normalize_arabic(entry.get('ayah_text',''))
        # if substring match
        if nq in nt:
            results.append(('substring', entry))
    return results

def find_matches_in_hadith(query, hdata):
    nq = normalize_arabic(query)
    results = []
    for entry in hdata:
        # hadithTxt or Matn
        txts = []
        if entry.get('hadithTxt'):
            txts.append(entry.get('hadithTxt'))
        if entry.get('Matn'):
            txts.append(entry.get('Matn'))
        for t in txts:
            nt = normalize_arabic(t)
            if nq in nt:
                results.append(('substring', entry))
                break
    return results

