# search for 'تأسف' variants in quran and hadith 
def search_token(tok, qdata, hdata):
    results_q = [e for e in qdata if normalize_arabic(tok) in normalize_arabic(e.get('ayah_text',''))]
    results_h = []
    for entry in hdata:
        for field in ('hadithTxt','Matn'):
            t = entry.get(field)
            if t and normalize_arabic(tok) in normalize_arabic(t):
                results_h.append((entry, field))
                break
    return results_q, results_h

